def _adjust_palette_lightness(palette, lightness_factor):
    from . import ImagePalette

    mode = palette.mode
    channels = len(mode)
    data = bytearray(palette.palette)
    for i in range(0, len(data), channels):
        for c in range(channels):
            if mode[c] == "A":
                continue
            data[i + c] = min(255, max(0, round(data[i + c] * lightness_factor)))
    return ImagePalette.ImagePalette(mode, bytes(data))


